mapper.select:
SELECT COUNT(GATE_CD) AS CNT
  FROM STOCOGHU
 WHERE GATE_CD = #{gateCd}

mapper.insert:
INSERT INTO STOCOGHU (
	  GATE_CD
    , GATE_NM
    , GATE_NM_ENG
    , DEL_FLAG
    , REG_USER_ID
    , MOD_USER_ID
    , GMT_CD
    , REG_DATE
    , MOD_DATE
) VALUES (
      UPPER(#{gateCd})
    , #{gateNm}
    , #{gateNmEng}
    , '0'
    , #{ses.userId}
    , #{ses.userId}
    , #{gmtCd}
    , SYSDATE
    , SYSDATE
)

mapper.update:
UPDATE STOCOGHU SET
	 MOD_USER_ID = #{ses.userId}
    ,DEL_FLAG = '0'
  ,GATE_NM = #{gateNm}
  ,GATE_NM_ENG = #{gateNmEng}
  ,GMT_CD = #{gmtCd}
    ,MOD_DATE = SYSDATE
WHERE GATE_CD = #{gateCd}

UPDATE STOCOGHU SET
	 DEL_FLAG = '1'
    ,MOD_USER_ID = #{ses.userId}
    ,MOD_DATE = SYSDATE
WHERE GATE_CD = #{gateCd}
